# Fallback final: si un idioma nuevo aun no tiene una frase exacta, usa ingles
# antes de volver al texto original espanol. Asi se evita UI mixta espanol/otro idioma.
def traducir_texto(texto, idioma):
    if idioma == 'es' or texto is None:
        return texto
    clave = str(texto)
    traduccion = BASE_TRANSLATIONS.get(idioma, {}).get(clave)
    if traduccion is not None:
        return traduccion
    traduccion_en = BASE_TRANSLATIONS.get('en', {}).get(clave)
    if traduccion_en is not None:
        return traduccion_en
    return clave

