# Si un texto ya fue traducido al ingles por una capa anterior y luego se cambia a
# otro idioma, se recupera la clave original en espanol y se traduce al idioma real.
_EN_REVERSE = None

def _english_reverse():
    global _EN_REVERSE
    if _EN_REVERSE is None:
        _EN_REVERSE = {}
        for _clave, _valor in BASE_TRANSLATIONS.get('en', {}).items():
            if isinstance(_valor, str) and _valor:
                _EN_REVERSE.setdefault(_valor, _clave)
    return _EN_REVERSE

def traducir_texto(texto, idioma):
    if texto is None:
        return texto
    texto = str(texto)
    if idioma == 'es':
        return texto
    tabla = BASE_TRANSLATIONS.get(idioma, {})
    if texto in tabla:
        return tabla[texto]
    origen = _english_reverse().get(texto)
    if origen and origen in tabla:
        return tabla[origen]
    if origen and idioma != 'en':
        return origen
    return texto

