_EN_REVERSE = None

def traducir_texto(texto, idioma):
    if texto is None:
        return texto
    texto = str(texto)
    if idioma == 'es':
        return texto
    tabla = BASE_TRANSLATIONS.get(idioma, {})
    if texto in tabla:
        return tabla[texto]
    origen = _english_reverse().get(texto)
    if origen and origen in tabla:
        return tabla[origen]
    if texto.startswith('Apply '):
        return f"{tabla.get('Aplicar', 'Apply')} {texto.split(' ', 1)[1]}"
    if texto.startswith('Level '):
        return f"{tabla.get('Nivel', 'Level')} {texto.split(' ', 1)[1]}"
    if origen and idioma != 'en':
        return origen
    return texto

