_EN_REVERSE = None

def traducir_texto(texto, idioma):
    if texto is None:
        return texto
    clave = str(texto)
    if idioma == 'es':
        return clave
    tabla = BASE_TRANSLATIONS.get(idioma, {})
    if clave in tabla:
        valor = tabla[clave]
        if not _valor_es_fallback_ingles(clave, valor, idioma):
            return valor
    if clave.startswith('OC alto '):
        return f"{traducir_texto('OC alto', idioma)} {clave.split(' ', 2)[2]}"
    origen = _english_reverse().get(clave)
    if origen:
        valor = tabla.get(origen)
        if valor and not _valor_es_fallback_ingles(origen, valor, idioma):
            return valor
        if idioma == 'en':
            return clave
        return origen
    if clave.startswith('Apply '):
        return f"{traducir_texto('Aplicar', idioma)} {clave.split(' ', 1)[1]}"
    if clave.startswith('Level '):
        return f"{traducir_texto('Nivel', idioma)} {clave.split(' ', 1)[1]}"
    if clave.startswith('Load '):
        salida = clave.replace('Load', traducir_texto('Carga', idioma), 1)
        return salida.replace('threads', traducir_texto('hilos', idioma))
    if clave.endswith(' threads'):
        return clave[:-8] + ' ' + traducir_texto('hilos', idioma)
    return clave

